INSERT INTO `carrera` VALUES (9,'Estudia la creación de software confiable y de calidad, basándose en métodos y técnicas de ingeniería, y brindando soporte operacional y de mantenimiento.',10,'Ingeniería de Software','Ingeniería','IRC, ICR, RIC, CIR, IER','software.jpg'),(10,'Estudia y comprende la realidad, con el enfoque de implementar u optimizar sistemas complejos. Puede también verse como la aplicación tecnológica de la teoría de sistemas a los esfuerzos de la ingeniería, adoptando en todo este trabajo el paradigma sistémico.',10,'Ingeniería de Sistemas','Ingeniería','IRC, ICR, RIC, CIR, RCI','sistema.jpg'),(11,'Emplea conocimientos de cálculo, mecánica, hidráulica y física para encargarse del diseño, construcción y mantenimiento de las infraestructuras emplazadas en el entorno, incluyendo carreteras, ferrocarriles, puentes, canales, presas, puertos, aeropuertos, diques y otras construcciones relacionadas.',10,'Ingeniería Civil','Ingeniería','RIC, RIE, RCI, IRC, RCE','ingenieriacivil.jpg'),(12,'Se ocupa de la optimización de procesos, sistemas u organizaciones complejos mediante el desarrollo, la mejora y la implementación de sistemas integrados de personas (recursos humanos), riqueza, conocimiento, información y equipamiento, energía, materiales y procesos.',10,'Ingeniería Industrial','Ingeniería','RIC, REC, RCE, IRC, ERC','ingenieriaindustrial.jpg'),(14,'Se ocupa de la extracción de los recursos minerales. Esta extracción es mediante técnicas y labores mineras de los recursos minerales. El conocimiento y el uso en la ingeniería de explosivos.',10,'Ingeniería de Minas','Ingeniería','RIE, RIC, RCE, IRC','ingenieriaminas.jpg'),(16,'Es el arte y la técnica de proyectar, diseñar y construir, modificando el hábitat humano y considerando criterios de estética, funcionalidad y uso del espacio arquitectónico, espacio urbano o paisa',10,'Arquitectura','Arquitectura','RIA, RAI, AIR, RIC, RAE','arquitectura.jpg'),(17,'Estudia los problemas del planeta de forma científica e integrada, teniendo en cuenta sus dimensiones científicas: químicas, físicas, ecológicas, biológicas, geológicas, sociales, económicas y tecnoló',10,'Ingeniería Ambiental','Ingeniería','IRC, RIC, ISC, RSC','ingenieriaambiental.jpg'),(18,'Trata el estudio y el análisis de la conducta y los procesos mentales de los individuos y de grupos humanos en distintas situaciones.',10,'Psicología','Psicología','ISA, SIA, IES, SEI','psicologia.jpg'),(19,'Profesión cuya actividad consiste en proyectar comunicaciones visuales destinadas a transmitir mensajes específicos a grupos sociales con objetivos determinados.',10,'Diseño Gráfico','Arte y Diseño','AIR, AIE, AEI, IAC, ACI','disenografico.jpg'),(20,'Disciplina que se enfoca en la planificación, organización y control de recursos de una organización, con el objetivo de alcanzar metas de manera eficiente y eficaz dentro de un entorno competitivo.',10,'Administración de Empresas','Administración','ESC, SEC, ECS, EIC, REC','adminempresas.jpg'),(21,'Es la ciencia que estudia al ser humano de una forma integral, en sus características físicas como animales y de su cultura.',10,'Antropología','Ciencias Sociales','IAS, ISA, AIS','abtropologia.jpg'),(22,'Tratan los asuntos extranjeros y las grandes cuestiones del sistema internacional en materia política, económica, jurídica y diplomática.',10,'Relaciones Internacionales','Negocios','EIS, SEC, IES','relacionesinternacionales.jpg'),(23,'Es la ciencia social que se encarga del análisis de la sociedad humana o población global.',10,'Sociología','Ciencias Sociales','ISC, SIE, SIC, ISE','sociologia.jpg'),(24,'Dominarás competencias avanzadas en pedagogía infantil, neurociencia del aprendizaje y metodologías innovadoras como el aprendizaje basado en proyectos, capacitándote para diseñar experiencias educativas enriquecedoras que potencien el desarrollo pleno y la felicidad de los niños de 0 a 5 años.',10,'Educación Inicial','Educación','SAI, SAC, ASE, SIA','educacioninicial.jpg'),(25,'Diseñada para jóvenes con iniciativa, responsabilidad y creatividad que acepten el reto de acompañar en su formación a niños y niñas entre 6 y 12 años de edad, que disfruten del trabajo con ellos, y que sean sensibles a sus necesidades, capaces de generar oportunidades de aprendizaje originales que desarrollen el inmenso potencial de los niños.',10,'Educación Primaria','Educación','SAI, SAC, SIA','educacionprimaria.jpg'),(26,'Forma profesionales con competencias en el diseño, ejecución y evaluación de los procesos de enseñanza aprendizaje, capaces de generar experiencias educativas significativas y respetuosas de los derechos, las características, los intereses y las necesidades de los adolescentes del país en el contexto global.',10,'Educación Secundaria','Educación','SIC, SIE, ISC, SAI','educacionsecundaria.jpg'),(27,'Se encarga del análisis del patrimonio y de la situación patrimonial, económica y financiera de una entidad, ya sea una empresa, organización o persona. Su finalidad es proporcionar información estructurada, fiable y relevante que facilite la toma de decisiones internas y el control externo de la gestión.',10,'Contabilidad','Ciencias Económicas','CIE, ECI, ICE, CEI','contabilidad.jpg'),(28,'Aporta al desarrollo de nuestro país. Genera nuevos conceptos de productos creados industrialmente para resolver las relaciones de forma–función, así como para optimizar su uso, funcionamiento, producción, sustentabilidad, venta y distribución.',10,'Diseño Industrial','Arte y Diseño','RAI, AIR, RIA, REA','disenoindustrial.jpg'),(29,'Desarrolla una visión integral sobre la creación, difusión y gestión del diseño y de la moda, explorando sus componentes culturales, estratégicos, creativos y comunicativos desde una propuesta de valoración sustantiva del patrimonio peruano de textiles, vestimenta y accesorios.',10,'Arte, Moda y Diseño Textil','Arte y Diseño','RAE, AER, ARE, SEA','artemodadiseño.jpg'),(30,'Forma creadores, productores e investigadores que conocen los procesos que hacen posible el diseño, la realización y sostenibilidad de proyectos de artes escénicas que conecten con el público e impacten en la sociedad.',10,'Creación y Producción Escénica','Artes Escénicas','ASE, RAE, REA','creacionescenica.jpg'),(31,'Estudia los procesos de producción, distribución y consumo de bienes y servicios en la sociedad. Intenta explicar cómo funcionan los mercados al asignar recursos que los individuos y la sociedad disponen para producir riqueza y alcanzar el bienestar de sus integrantes.',10,'Economía','Ciencias Económicas','IEC, ICE, EIC, CEI','economia.jpg'),(32,'Estudia la asignación de capital o inversión entre agentes económicos para atender las necesidades de financiamiento. Estos agentes pueden ser individuos, empresas, otro tipo de entidades o, inclusive Estados.',10,'Finanzas','Ciencias Económicas','IEC, ICE, EIC, CIE','finanzas.jpg'),(33,'Estudia y permite comprender las relaciones de poder en general, y, en particular, el funcionamiento de las instituciones públicas y el proceso de toma de decisiones de Estado y de política pública, en el que intervienen diversos actores políticos y sociales.',10,'Ciencias Políticas','Ciencias Sociales','EIS, IES, SEC, ISC','cienciaspoliticas.jpg'),(34,'Como ingeniero de telecomunicaciones, te encargarás de planificar, diseñar y de mantener operativa esta infraestructura. También, construirás y configurarás las aplicaciones que permitan su funcionamiento, y determinen los costos y tiempos de operación de un servicio eficaz, seguro y eficiente.',10,'Ingeniería de Telecomunicaciones','Ingeniería','IRC, ICR, RIC, CIR','ingenieriatelecomunicaciones.jpg'),(35,'Se encarga de resolver problemas de la ingeniería tales como el control de procesos industriales y de sistemas electrónicos de potencia, instrumentación y control, así como la transformación de electricidad para el funcionamiento de diversos aparatos eléctricos.',10,'Ingeniería Electrónica','Ingeniería','RIC, IRC, RIE, CIR','ingenieriaelectronica.jpg'),(36,'Es la rama de la ingeniería que se dedica a los proyectos de ingeniería relacionados con los procesos, materiales y recursos de la tierra (y los planetas).',10,'Ingeniería Geológica','Ingeniería','RCI, RIC','ingenieriageologica.jpg'),(37,'Disciplina que estudia y perfecciona diversos principios como la termodinámica, transferencia de calor, mecánica, análisis estructural, trigonometría, teoría de control, etc. Estos principios sirve para el diseño y análisis de diversos elementos usados en la actualidad como maquinaria térmica, hidraúlica, robótica, etc.',10,'Ingeniería Mecánica','Ingeniería','RIE, RIC, IRC, RCE','ingenieriamecanica.jpg'),(38,'Engloba las ramas de sistemas, electrónica, mecánica y control; ya que tanto sistemas de control como procesos inteligentes con el objetivo de crear maquinaria más compleja para facilitar las actividades del ser humano.',10,'Ingeniería Mecatrónica','Ingeniería','RIE, IRC, RIC, IER','ingenieriamecatronica.jpg'),(39,'Se encarga del estudio, diseño, manutención, evaluación, optimización, simulación, construcción y operación de todo tipo de elementos en la industria de procesos, que es aquella relacionada con la producción industrial de compuestos y productos cuya elaboración requiere de sofisticadas transformaciones físicas y químicas de la materia.',10,'Ingeniería Química','Ingeniería','IRC, RIC, ICR, ISC','ingenieriaquimica.jpg'),(40,'Es una rama de la ingeniería mecánica aplicada a los vehículos, que incorpora elementos de mecánica, electricidad, electrónica, software e ingeniería de seguridad aplicándolos al diseño, manufactura y operación de motocicletas, automóviles, autobuses y camiones y sus respectivos subsistemas de ingeniería.',10,'Ingeniería Automotriz','Ingeniería','RIE, RIC, RCE','ingeniariaautomotriz.jpg'),(41,'Esta ingeniería se dedica principalmente al diseño y construcción de productos sanitarios y tecnologías sanitarias tales como los equipos médicos, las prótesis, dispositivos médicos, dispositivos de diagnóstico (imagenología médica) y de terapia.',10,'Ingeniería Biomédica','Ingeniería','IRE, IRC, ISR, RIC','ingenieriabiomedica.jpg'),(42,'Es el campo de la ingeniería que se ocupa del estudio y la aplicación de la electricidad, electromagnetismo, electromecánica y la electrónica a sistemas eléctricos de potencia.',10,'Ingeniería Eléctrica','Ingeniería','RIC, IRC, RIE, CIR','ingenieriaelectrica.jpg'),(43,'Aplica conocimientos científicos, tecnológicos y empresariales, y que se ocupa de la optimización de uso de recursos humanos, técnicos, informativos así como el manejo y gestión óptimos de los sistemas empresariales.',10,'Ingeniería Empresarial','Ingeniería','EIC, EIR, ESC, REC','ingenieriaempresarial.jpg'),(44,'Es la ciencia de la salud dedicada a la prevención, diagnóstico, pronóstico y tratamiento de las enfermedades, lesiones y problemas de salud de los seres humanos.',14,'Medicina','Medicina','ISR, SIR, IRS, RSI','medicina.jpg'),(45,'Estudia los patrones, propiedades, estructuras y relaciones presentes en sistemas lógicos y abstractos creados por los humanos, conceptos tales como cantidad, forma, espacio y número se podrían considerar como el objeto de estudio de la matemática.',10,'Matemática','Ciencias Básicas','IRC, RCI, ICR, CRI, CIR','matematica.jpg'),(46,'La estadística se emplea como herramienta metodológica para la recolección, organización, análisis, interpretación y presentación de los datos obtenidos durante la investigación. Este proceso permite extraer conclusiones a partir de muestras y formular inferencias sobre las poblaciones de origen.',10,'Estadística','Ciencias Básicas','IRC, CIR, CIS, RCI, ISC','esdistica.jpg'),(47,'Estudia la naturaleza de los componentes y fenómenos más fundamentales del Universo como lo son la energía, la materia, la fuerza, el movimiento, el espacio-tiempo, las magnitudes y propiedades naturales fundamentales y las interacciones fundamentales.',10,'Física','Ciencias Básicas','IRC, RIC, ICR, CRI, CIR','fisica.jpg'),(48,'Estudia y analiza la composición, estructura y propiedades de la materia, ya sea en forma de elementos, especies, compuestos, mezclas u otras sustancias, así como los cambios que estas experimentan durante las reacciones y su relación con la energía química.',10,'Química','Ciencias Básicas','IRC','quimica.jpg'),(49,'Representa historias actuadas frente a los espectadores o frente a una cámara usando una combinación de discurso, gestos, escenografía, música, sonido y espectáculo.',10,'Teatro','Artes Escénicas','ARS, ASR, ESA, RSA, SRA','teatro.jpg'),(50,'Es un arte donde se utiliza el movimiento del cuerpo, normalmente con música, como una forma de expresión y de interacción social con fines de entretenimiento y artísticos.',10,'Danza','Artes Escénicas','ARS, ASR, AER','danza.jpg'),(51,'Es el arte de crear y organizar sonidos y silencios que se combinan para formar melodías, ritmos y armonías en el tiempo mediante la intervención de complejos procesos psicoanímicos.',10,'Música','Artes Escénicas','ASE, RAS','musica.jpg'),(52,'Disciplina que se dedica al cuidado y atención de enfermos y heridos, así como a otras tareas de asistencia sanitaria, clínicas y a la promoción de la salud y prevención de la enfermedad.',10,'Enfermería','Ciencias de la Salud','SIR, ISR, RIS, SRC','enfermeria.jpg'),(53,'Un químico farmacéutico se encarga de desarrollar productos farmacéuticos, analizar sus efectos en el cuerpo humano y aplicar conocimientos científicos, técnicos y humanísticos.',10,'Farmacia y Bioquímica','Ciencias de la Salud','IRC, ISR, RIC, RIS, RSI','farmaciabioquimica.jpg'),(54,'Un nutricionista dietético orienta a las personas en la adopción de una alimentación equilibrada, adaptada a sus necesidades, y en la gestión de problemas de salud vinculados a la dieta.',10,'Nutrición y Dietética','Ciencias de la Salud','SIR, ISR, SIC, RSI, IRS','nutriciondietetica.jpg'),(55,'Se encarga del embarazo, el parto y el puerperio (incluyendo la atención del recién nacido), además de la salud sexual y reproductiva de la mujer a lo largo de toda su vida.',10,'Obstetricia','Ciencias de la Salud','SIR, ISR, SAI','obstetricia.jpg'),(56,'Se encarga del diagnóstico, tratamiento y prevención de las enfermedades del aparato estomatognático, el cual incluye además de los dientes, las encías, el tejido periodontal, el maxilar superior, el maxilar inferior y la articulación temporomandibular.',10,'Odontología','Ciencias de la Salud','ISR, SIR, RIC','odontologia.jpg'),(57,'Ofrece tratamiento y rehabilitación física para diagnosticar, prevenir y tratar síntomas de múltiples patologías, tanto agudas como crónicas, por medio de ejercicios terapéuticos[2] y agentes físicos como la electricidad, ultrasonido, láser, calor, frío, agua y técnicas manuales como estiramientos, tracciones y masoterapia.',10,'Terapia Física','Ciencias de la Salud','RSC, SIR, RSR','terapiafisica.jpg'),(58,'Se enfoca en la protección de la infraestructura computacional y todo lo vinculado con la misma, y especialmente la información contenida en una computadora o circulante a través de las redes de computadoras.',10,'Ciberseguridad','Computación','RIC','ciberseguridad.jpg'),(59,'Utiliza matemáticas, estadística, computación científica, método científico, procesos ingenieriles y algoritmos para obtener (recolectar o extraer), tratar, analizar y presentar informes a partir de datos ruidosos, estructurados y no estructurados.',10,'Ciencia de Datos','Computación','IRC, RCI, ICS','cienciadatos.jpg'),(60,'En informática, los sistemas de información ayudan a administrar, recolectar, recuperar, procesar, almacenar y distribuir información relevante para los procesos fundamentales y las particularidades de cada organización.',10,'Sistemas de Información','Computación','RIC','sistemainformacion.jpg'),(61,'Son un conjunto de ciencias formales que estudian los fundamentos teóricos de la información y de la computación, así como sus aplicaciones prácticas en los sistemas de información y en los sistemas informáticos.',10,'Ciencias de la Computación','Computación','IRC, RCI, IRE, ICR, CIR','cienciacomputacion.jpg'),(62,'Analizan, estudian y discuten los fenómenos relacionados con la información y el efecto de la acción de la comunicación humana. Se encargan de observar y examinar los medios de difusión masivos (desde su legislación, hasta la producción y recepción de los contenidos), las industrias culturales, el consumo y el conjunto semiótico que estos construyen.',10,'Ciencias de la Comunicación','Comunicaciones','AES, EAS, SAC, IAE','cienciacomunicacion.jpg'),(63,'Un comunicador audiovisual planifica, estructura y realiza productos desde una perspectiva creativa, estética y tecnológica, y los expresa a través de imágenes y sonidos. Para tal fin, integra el uso de los lenguajes audiovisuales, la apreciación estética y el conocimiento de las estructuras narrativas.',10,'Comunicación Audiovisual','Comunicaciones','AER, EAS, AIR, ASE','comunicacionaudiovisual.jpg'),(64,'Un publicista se ocupa del diseño y aplicación de estrategias de comunicación basadas en la filosofía de la organización y en el estudio de los públicos y de sus mercados. De esta forma, otorga mayor credibilidad a las marcas y confiabilidad a sus productos, y eleva su valor, lo que promueve su venta y estimula el cambio de los hábitos de consumo.',10,'Publicidad','Comunicaciones','EIA, ASE, AIE, EAS','publicidad.jpg'),(65,'Es una actividad profesional que consiste en la obtención, investigación, tratamiento, difusión y análisis de la información, a través de los medios de comunicación social como la prensa, la radio, la televisión, el Internet, entre otros.',10,'Periodismo','Comunicaciones','IAS, IAC, ISA, AIC, ASC','periodismo.jpg'),(66,'Un abogado se encarga de dar asesoramiento jurídico, representar legalmente a sus clientes y defiende sus derechos e intereses en los tribunales.',10,'Derecho','Derecho','ESC, SEC, EIS, ICS','derecho.jpeg'),(67,'La gastronomía además de estudiar el cómo las personas están conectadas en cuanto a su nutrición, también estudia su procedencia. Esto quiere decir que se estudian factores como las costumbres, el lugar, credo religioso e historia, estos cuatro componentes son también los objetos de estudios que la gastronomía utiliza para estudiar a fondo su procedencia.',10,'Gastronomía','Gastronomía, Hotelería y Turismo','RSE, RES, AER, SER','gatronomia.jpg'),(68,'Es el nombre genérico de las actividades económicas consistentes en la prestación de servicios ligados al alojamiento, hospitalidad y la alimentación esporádicos, muy usualmente ligados al turismo.',10,'Hotelería','Gastronomía, Hotelería y Turismo','RES, RSE, ESC','hoteleria.jpg'),(69,'Podrás ser un profesional con un alto sentido ético que es capaz de relacionarse óptimamente con el entorno. De esta forma, tu relación con el mismo se dará mediante la gestión de proyectos y de destinos turísticos, así como de experiencias innovadoras para cada tipo de turista.',10,'Turismo','Gastronomía, Hotelería y Turismo','SEA, ESA, ASE','turismo.jpg'),(70,'La carrera de Gestión se centra en la creación de valor para todo tipo de organizaciones, brindando soluciones y aprovechando oportunidades. Prepara a sus estudiantes para innovar y lograr objetivos organizacionales considerando el desarrollo, la ética y la sostenibilidad.',10,'Gestión','Gestión y Alta Dirección','SCE, AEC, ACE, SEC, SCE','gestion.jpg'),(71,'Podrás tener una reflexión propia y creativa con respecto a tu realidad y podrás convertirte en un investigador que cuestiona los presupuestos sobre los cuales se fundan nuestras creencias y acciones.',10,'Filosofía','Letras y Ciencias Humanas','IAC, IAS, ISA, ISC','filosofia.jpg'),(72,'Es una ciencia que estudia, reconstruye y analiza los procesos históricos de las sociedades a través del tiempo, para poder comprender el presente con una visión de futuro. Su estudio forma la conciencia histórica de los ciudadanos.',10,'Historia','Letras y Ciencias Humanas','IAC, IAS, ISC, CAI, AIC','historia.jpg'),(73,'Estudian los aspectos esenciales de la existencia humana, incluyendo la cultura, la sociedad, el pensamiento, el arte, la historia, la literatura, la filosofía y otros ámbitos característicos de la vida y expresión humana.',10,'Humanidades','Letras y Ciencias Humanas','IAS, ISA, IAC, AIS','humanidades.jpg'),(74,'La lingüística se interesa por analizar la estructura del lenguaje, estudiar su evolución histórica, y observar las relaciones entre el lenguaje y la sociedad.',10,'Lingüística','Letras y Ciencias Humanas','IAS, ISA, IAC, ICA, AIS','linguistica.jpg'),(75,'La literatura se interesa por los mecanismos creativos que permiten el uso de la lengua con una finalidad estética, la formación de tradiciones discursivas y el lugar social de la obra literaria.',10,'Literatura','Letras y Ciencias Humanas','IAC, IAS, ISA, ICA, AIS','literatura.jpg'),(76,'Se encarga de mejorar la visibilidad de una empresa, atraer nuevos clientes, fidelizar a los existentes y aumentar las ventas.',10,'Administración y Marketing','Administración','EIA, ASE, ESA, EIC','adminmarketing.jpg');
/*!40000 ALTER TABLE `carrera` ENABLE KEYS */;
UNLOCK TABLES;

